class Solution:
    def maximumCandies(self, candies, k):
        """
        :type candies: List[int]
        :type k: int
        :rtype: int
        """
        def canAllocate(num_candies_each):
            # Check if we can give num_candies_each to k children
            total_children = 0
            for pile in candies:
                total_children += pile // num_candies_each
                if total_children >= k:
                    return True
            return total_children >= k

        left, right = 1, sum(candies) // k
        result = 0

        while left <= right:
            mid = (left + right) // 2
            if canAllocate(mid):
                result = mid
                left = mid + 1
            else:
                right = mid - 1

        return result
